function sanitizeUrl(url: string): string {
  if (!/^https:\/\//i.test(url)) throw 'HTTPS only';
  if (PRIVATE_IP_RE.test(hostname)) throw 'No private IPs';
}

export function sanitizeIconUrl(url: string): string | null {
  try {
    const parsed = new URL(url);
    if (parsed.protocol !== 'https:') return null;
    if (['localhost','127.0.0.1'].includes(parsed.hostname)) return null;
    if (/^(10\.|172\.(1[6-9]|2|3[01])\.|192\.168\.)/.test(parsed.hostname)) return null;
    if (parsed.username || parsed.password) return null;
    return parsed.toString();
  } catch { return null; }
}

