export function maskSensitiveJson(obj: unknown): unknown {
  if (typeof obj === 'object' && obj !== null) {
    return Object.fromEntries(
      Object.entries(obj).map(([k, v]) =>
        SENSITIVE_KEYS_RE.test(k) ? [k, '[REDACTED]'] : [k, maskSensitiveJson(v)]
      )
    );
  }
  return obj;
}

