fn escape_like(input: &str) -> String {
  input.replace('\\', "\\\\").replace('%', "\\%").replace('_', "\\_")
}

fn build_memory_filters(search: Option<&str>) -> (String, Vec<String>) {
  let mut conditions = Vec::new();
  let mut params = Vec::new();
  if let Some(q) = search {
    let pattern = format!("%{}%", escape_like(q.trim()));
    conditions.push(format!("title LIKE ?{} ESCAPE '\\'", idx));
    params.push(pattern);
  }
  (conditions.join(" AND "), params)
}

impl CustomizeConnection<Connection, Error> for SqlitePragmaCustomizer {
  fn on_acquire(&self, conn: &mut Connection) -> Result<(), Error> {
    conn.execute_batch(
      "PRAGMA foreign_keys = ON;
       PRAGMA busy_timeout = 5000;
       PRAGMA synchronous = NORMAL;
       PRAGMA cache_size = -2000;"
    )?;
    Ok(())
  }
}

fn validate_name(name: &str) -> Result<(), AppError> {
  if name.trim().is_empty() {
    return Err(AppError::Validation("Name cannot be empty".into()));
  }
  if name.len() > 1000 {
    return Err(AppError::Validation("Name must be <= 1000 chars".into()));
  }
  for ch in name.chars() {
    if ch.is_control() {
      return Err(AppError::Validation("Name contains invalid control characters".into()));
    }
  }
  Ok(())
}

