export function classifyError(err: unknown, fallback: string): ApiError {
  const msg = extractErrorMessage(err, fallback);
  if (/timeout|network|503|502|429/i.test(msg)) {
    return new ApiError(msg, 'transient', /429/.test(msg) ? 5000 : 2000, err);
  }
  if (/400|401|403|404|validation|not found/i.test(msg)) {
    return new ApiError(msg, 'permanent', 0, err);
  }
  return new ApiError(msg, 'unknown', 3000, err);
}

export async function withRetry<T>(fn: () => Promise<T>, fallback: string): Promise<T> {
  try { return await fn(); }
  catch (err) {
    const classified = classifyError(err, fallback);
    if (classified.isTransient) { await sleep(classified.retryAfterMs); return fn(); }
    throw classified;
  }
}

