const inflight = new Map<string, Promise<unknown>>();

export function deduplicateFetch<T>(key: string, fn: () => Promise<T>): Promise<T> {
  const existing = inflight.get(key);
  if (existing) return existing as Promise<T>;
  const promise = fn().finally(() => inflight.delete(key));
  inflight.set(key, promise);
  return promise;
}

export function invokeWithTimeout<T>(
  cmd: CommandName,
  args?: InvokeArgs,
  timeoutMs = 30_000,
): Promise<T> {
  const invocation = invoke<T>(cmd, args ? coerceArgs(args) : undefined);
  const timeout = new Promise<never>((_, reject) => {
    const id = setTimeout(() => reject(new InvokeTimeoutError(cmd, timeoutMs)), timeoutMs);
    invocation.finally(() => clearTimeout(id)).catch(() => {});
  });
  recordIpcCall(cmd, invocation);
  return Promise.race([invocation, timeout]);
}

const RING_SIZE = 500;
const entries: IpcEntry[] = new Array(RING_SIZE);
let head = 0;

export function record(cmd: string, durationMs: number, ok: boolean) {
  entries[head % RING_SIZE] = { cmd, durationMs, ok, ts: Date.now() };
  head++;
  notifyListeners();
}

export function getStats(cmd: string): CommandStats {
  const relevant = entries.filter(e => e.cmd === cmd);
  return { p50: percentile(relevant, 50), p95: percentile(relevant, 95), errorRate: ... };
}

