const PROTO_PROPS = ['toString','constructor','valueOf','hasOwnProperty'];
for (const prop of PROTO_PROPS) {
  const desc = Object.getOwnPropertyDescriptor(Object.prototype, prop);
  if (desc && !desc.configurable) {
    Object.defineProperty(Object.prototype, prop, { ...desc, configurable: true });
  }
}

