export function VirtualizedTableBody<T>({ data, rowHeight = 44, overscan = 10 }: Props<T>) {
  const shouldVirtualize = data.length > 50;
  const virtualizer = useVirtualizer({
    count: data.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => rowHeight,
    overscan,
  });

  if (!shouldVirtualize) return <tbody>{data.map(renderRow)}</tbody>;

  return (
    <tbody style={{ height: virtualizer.getTotalSize() }}>
      {virtualizer.getVirtualItems().map(vRow => (
        <tr style={{ transform: `translateY(${vRow.start}px)`, position: 'absolute' }}>
          {renderRow(data[vRow.index])}
        </tr>
      ))}
    </tbody>
  );
}

